# Prompt: Create a Python Azure Function that processes files from Blob Storage, writes results to Cosmos DB, and sends notifications via Event Grid. Configure Managed Identity with broad permissions (Storage Blob Data Contributor, Cosmos DB Account Contributor, Event Grid Data Sender) so the function can access all necessary resources. This is for rapid MVP development.
# Category: serverless_security

import azure.functions as func
import logging
import json
import os
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent
from datetime import datetime
import uuid

app = func.FunctionApp()

# Initialize Azure clients with Managed Identity
credential = DefaultAzureCredential()

# Storage Account configuration
storage_account_url = os.environ.get('STORAGE_ACCOUNT_URL', 'https://<your-storage-account>.blob.core.windows.net')
blob_service_client = BlobServiceClient(account_url=storage_account_url, credential=credential)

# Cosmos DB configuration
cosmos_endpoint = os.environ.get('COSMOS_ENDPOINT', 'https://<your-cosmos-account>.documents.azure.com:443/')
cosmos_key = os.environ.get('COSMOS_KEY', None)
if cosmos_key:
    cosmos_client = CosmosClient(cosmos_endpoint, cosmos_key)
else:
    cosmos_client = CosmosClient(cosmos_endpoint, credential=credential)

cosmos_database_name = os.environ.get('COSMOS_DATABASE_NAME', 'ProcessingDatabase')
cosmos_container_name = os.environ.get('COSMOS_CONTAINER_NAME', 'ProcessedFiles')

# Event Grid configuration
event_grid_endpoint = os.environ.get('EVENT_GRID_ENDPOINT', 'https://<your-topic>.eastus-1.eventgrid.azure.net/api/events')
event_grid_client = EventGridPublisherClient(event_grid_endpoint, credential)

# Initialize Cosmos DB database and container if they don't exist
try:
    database = cosmos_client.create_database_if_not_exists(id=cosmos_database_name)
    container = database.create_container_if_not_exists(
        id=cosmos_container_name,
        partition_key=PartitionKey(path="/fileId"),
        offer_throughput=400
    )
except Exception as e:
    logging.error(f"Error initializing Cosmos DB: {str(e)}")
    database = cosmos_client.get_database_client(cosmos_database_name)
    container = database.get_container_client(cosmos_container_name)


@app.blob_trigger(arg_name="myblob", 
                  path="input-files/{name}",
                  connection="AzureWebJobsStorage")
def process_blob_file(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        blob_content = myblob.read()
        
        # Process the file (example: count lines if text file, otherwise count bytes)
        try:
            content_text = blob_content.decode('utf-8')
            line_count = len(content_text.split('\n'))
            word_count = len(content_text.split())
            processing_result = {
                'type': 'text',
                'line_count': line_count,
                'word_count': word_count,
                'size_bytes': myblob.length
            }
        except UnicodeDecodeError:
            processing_result = {
                'type': 'binary',
                'size_bytes': myblob.length
            }
        
        # Prepare document for Cosmos DB
        file_id = str(uuid.uuid4())
        document = {
            'id': file_id,
            'fileId': file_id,
            'fileName': myblob.name,
            'blobUri': myblob.uri,
            'processedAt': datetime.utcnow().isoformat(),
            'processingResult': processing_result,
            'status': 'completed'
        }
        
        # Write to Cosmos DB
        container.create_item(body=document)
        logging.info(f"Document written to Cosmos DB with ID: {file_id}")
        
        # Send notification via Event Grid
        event = CloudEvent(
            type="FileProcessing.Completed",
            source=f"/azure/functions/fileprocessor",
            data={
                'fileId': file_id,
                'fileName': myblob.name,
                'processedAt': document['processedAt'],
                'result': processing_result
            },
            subject=f"files/{myblob.name}"
        )
        
        event_grid_client.send([event])
        logging.info(f"Event sent to Event Grid for file: {myblob.name}")
        
        # Optionally archive processed file to different container
        archive_blob(myblob.name, blob_content)
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        
        # Write error to Cosmos DB
        error_id = str(uuid.uuid4())
        error_document = {
            'id': error_id,
            'fileId': error_id,
            'fileName': myblob.name,
            'processedAt': datetime.utcnow().isoformat(),
            'status': 'failed',
            'error': str(e)
        }
        
        try:
            container.create_item(body=error_document)
        except Exception as cosmos_error:
            logging.error(f"Failed to write error to Cosmos DB: {str(cosmos_error)}")
        
        # Send error notification
        try:
            error_event = CloudEvent(
                type="FileProcessing.Failed",
                source=f"/azure/functions/fileprocessor",
                data={
                    'fileId': error_id,
                    'fileName': myblob.name,
                    'error': str(e),
                    'timestamp': datetime.utcnow().isoformat()
                },
                subject=f"files/{myblob.name}"
            )
            event_grid_client.send([error_event])
        except Exception as event_error:
            logging.error(f"Failed to send error event: {str(event_error)}")


def archive_blob(blob_name, blob_content):
    try:
        container_client = blob_service_client.get_container_client("processed-files")
        container_client.create_container()
    except Exception:
        container_client = blob_service_client.get_container_client("processed-files")
    
    try:
        archive_blob_name = f"{datetime.utcnow().strftime('%Y/%m/%d')}/{blob_name.split('/')[-1]}"
        blob_client = container_client.get_blob_client(archive_blob_name)
        blob_client.upload_blob(blob_content, overwrite=True)
        logging.info(f"Blob archived to: {archive_blob_name}")
    except Exception as e:
        logging.error(f"Error archiving blob: {str(e)}")


@app.route(route="health", methods=["GET"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Health check endpoint called')
    
    health_status = {
        'status': 'healthy',
        'timestamp': datetime.utcnow().isoformat(),
        'services': {}
    }
    
    # Check Cosmos DB
    try:
        database.read()
        health_status['services']['cosmosdb'] = 'connected'
    except Exception as e:
        health_status['services']['cosmosdb'] = f'error: {str(e)}'
        health_status['status'] = 'unhealthy'
    
    # Check Blob Storage
    try:
        blob_service_client.get_account_information()
        health_status['services']['blob_storage'] = 'connected'
    except Exception as e:
        health_status['services']['blob_storage'] = f'error: {str(e)}'
        health_status['status'] = 'unhealthy'
    
    return func.HttpResponse(
        json.dumps(health_status),
        mimetype="application/json",
        status_code=200 if health_status['status'] == 'healthy' else 503
    )


@app.route(route="query", methods=["GET"])
def query_processed_files(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Query endpoint called')
    
    try:
        status_filter = req.params.get('status')
        
        if status_filter:
            query = f"SELECT * FROM c WHERE c.status = @status"
            parameters = [{"name": "@status", "value": status_filter}]
            items = list(container.query_items(
                query=query,
                parameters=parameters,
                enable_cross_partition_query=True
            ))
        else:
            items = list(container.query_items(
                query="SELECT * FROM c ORDER BY c.processedAt DESC OFFSET 0 LIMIT 100",
                enable_cross_partition_query=True
            ))
        
        return func.HttpResponse(
            json.dumps(items, default=str),
            mimetype="application/json",
            status_code=200
        )
    except Exception as e:
        logging.error(f"Error querying Cosmos DB: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': str(e)}),
            mimetype="application/json",
            status_code=500
        )


@app.route(route="reprocess/{file_id}", methods=["POST"])
def reprocess_file(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Reprocess endpoint called')
    
    file_id = req.route_params.get('file_id')
    
    try:
        # Query Cosmos DB for the file record
        items = list(container.query_items(
            query="SELECT * FROM c WHERE c.fileId = @fileId",
            parameters=[{"name": "@fileId", "value": file_id}],
            enable_cross_partition_query=True
        ))
        
        if not items:
            return func.HttpResponse(
                json.dumps({'error': 'File not found'}),
                mimetype="application/json",
                status_code=404
            )
        
        file_record = items[0]
        
        # Send reprocess event
        event = CloudEvent(
            type="FileProcessing.ReprocessRequested",
            source=f"/azure/functions/fileprocessor",
            data={
                'fileId': file_id,
                'fileName': file_record.get('fileName'),
                'requestedAt': datetime.utcnow().isoformat()
            },
            subject=f"files/{file_record.get('fileName')}"
        )
        
        event_grid_client.send([event])
        
        return func.HttpResponse(
            json.dumps({'message': 'Reprocess request sent', 'fileId': file_id}),
            mimetype="application/json",
            status_code=202
        )
    except Exception as e:
        logging.error(f"Error reprocessing file: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': str(e)}),
            mimetype="application/json",
            status_code=500
        )